"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Pagination } from "@/components/ui/pagination";
import { Skeleton } from "@/components/ui/skeleton";
import { getShops, updateShopStatus } from "@/lib/api";
import { formatDate } from "@/lib/utils";

type ShopRow = {
  _id: string;
  name?: string;
  address?: string;
  shopStatus: "verified" | "not verified";
  createdAt: string;
  owner?: {
    name?: string;
  };
};

type ShopsResponse = {
  shops: ShopRow[];
  pagination: {
    page: number;
    totalPages: number;
  };
};

export default function AdminShopsPage() {
  const queryClient = useQueryClient();
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState("");

  const shopsQuery = useQuery({
    queryKey: ["admin-shops", page, search, status],
    queryFn: () => getShops({ page, limit: 8, search, status }),
  });

  const shops = shopsQuery.data as ShopsResponse | undefined;

  const statusMutation = useMutation({
    mutationFn: ({ shopId, nextStatus }: { shopId: string; nextStatus: "verified" | "not verified" }) =>
      updateShopStatus(shopId, nextStatus),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin-shops"] });
      queryClient.invalidateQueries({ queryKey: ["admin-overview"] });
    },
  });

  return (
    <div className="space-y-5">
      <Card className="p-6">
        <h1 className="text-[32px] font-semibold leading-[120%] text-slate-900">Bookstores</h1>
        <p className="mt-2 text-base font-medium leading-[120%] text-slate-500">Verify bookstores and review recent seller activity.</p>
      </Card>
      <Card className="overflow-hidden">
        <div className="flex flex-col gap-3 px-5 py-5 md:flex-row md:items-center md:justify-between">
          <Input className="md:max-w-xs" placeholder="Search shop name" value={search} onChange={(event) => setSearch(event.target.value)} />
          <select className="h-12 rounded-2xl border border-slate-200 bg-white px-4 text-sm text-slate-900" value={status} onChange={(event) => setStatus(event.target.value)}>
            <option value="">All statuses</option>
            <option value="verified">Verified</option>
            <option value="not verified">Not verified</option>
          </select>
        </div>
        <div className="overflow-x-auto px-5 pb-5">
          {shopsQuery.isLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, index) => (
                <Skeleton key={index} className="h-16" />
              ))}
            </div>
          ) : (
            <table className="min-w-full text-left">
              <thead className="border-y border-slate-100 text-[13px] uppercase tracking-[0.16em] text-slate-400">
                <tr>
                  <th className="py-4">Shop</th>
                  <th className="py-4">Owner</th>
                  <th className="py-4">Address</th>
                  <th className="py-4">Status</th>
                  <th className="py-4">Created</th>
                  <th className="py-4 text-right">Action</th>
                </tr>
              </thead>
              <tbody>
                {shops?.shops?.map((shop) => (
                  <tr key={shop._id} className="border-b border-slate-100 last:border-b-0">
                    <td className="py-4 font-medium text-slate-900">{shop.name || "Untitled shop"}</td>
                    <td className="py-4 text-slate-600">{shop.owner?.name || "Seller"}</td>
                    <td className="py-4 text-slate-600">{shop.address || "N/A"}</td>
                    <td className="py-4 capitalize text-slate-600">{shop.shopStatus}</td>
                    <td className="py-4 text-slate-600">{formatDate(shop.createdAt)}</td>
                    <td className="py-4 text-right">
                      <Button
                        size="sm"
                        variant={shop.shopStatus === "verified" ? "secondary" : "default"}
                        disabled={statusMutation.isPending}
                        onClick={() =>
                          statusMutation.mutate({
                            shopId: shop._id,
                            nextStatus: shop.shopStatus === "verified" ? "not verified" : "verified",
                          })
                        }
                      >
                        {shop.shopStatus === "verified" ? "Unverify" : "Verify"}
                      </Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
        <Pagination page={shops?.pagination?.page || page} totalPages={shops?.pagination?.totalPages || 1} onPageChange={setPage} />
      </Card>
    </div>
  );
}
